"use strict";parserFactory.register("m.mywuxiaworld.com",()=>new MMyWwuxiaWorldParser);class MMyWwuxiaWorldParser extends Parser{constructor(){super()}async getChapterUrls(t){return[...(await HttpClient.wrapFetch(t.baseURI+"dir.html")).responseXML.querySelectorAll("div.chapter-list a")].map(t=>util.hyperLinkToChapter(t))}findContent(t){return t.querySelector("div.pt-read-cont")}extractAuthor(t){let e=t.querySelector("div.pt-bookdetail a");return null===e?super.extractAuthor(t):e.textContent}findChapterTitle(t){return t.querySelector("div.pt-read div").textContent}findCoverImageUrl(t){return util.getFirstImgSrc(t,"div.pt-bookdetail")}getInformationEpubItemChildNodes(t){return[...t.querySelectorAll("div.pt-bookdetail > div.flex-item, span.pt-book-intro")]}}